package com.example.pricing_calculation.service;
import com.example.pricing_calculation.domain.*;import com.example.pricing_calculation.dto.IncidentDtos.*;import com.example.pricing_calculation.repository.*;import java.time.LocalDateTime;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class UnifiedIncidentService {private static final Set<String>TYPES=Set.of("LOST_TICKET","WRONG_PLATE","OVERTIME","WRONG_ZONE","UNPAID","WRONG_VEHICLE_INFO","OCCUPIED_SLOT","INCIDENT","COMPLAINT","SUGGESTION","OTHER");private final IncidentReportRepository incidents;private final PaymentModuleParkingSessionRepository sessions;public UnifiedIncidentService(IncidentReportRepository incidents,PaymentModuleParkingSessionRepository sessions){this.incidents=incidents;this.sessions=sessions;}@Transactional(readOnly=true)public List<IncidentResponse>list(String status){return incidents.findAll().stream().filter(x->status==null||status.equalsIgnoreCase(x.getStatus())).map(IncidentResponse::from).toList();}@Transactional public IncidentResponse create(UserAccount staff,IncidentRequest r){if(r==null||r.incidentType()==null)throw new BadRequestException("incidentType is required");String type=r.incidentType().toUpperCase();if(!TYPES.contains(type))throw new BadRequestException("incidentType must be one of "+TYPES);IncidentReport x=new IncidentReport();if(r.sessionId()!=null)x.setSession(sessions.findById(r.sessionId()).orElseThrow(()->new ResourceNotFoundException("Session not found: "+r.sessionId())));x.setReportedBy(staff);x.setIncidentType(type);x.setDescription(r.description());x.setPenaltyAmount(r.penaltyAmount());x.setStatus("OPEN");x.setCreatedAt(LocalDateTime.now());return IncidentResponse.from(incidents.save(x));}@Transactional public IncidentResponse resolve(UserAccount staff,Long id){IncidentReport x=incidents.findById(id).orElseThrow(()->new ResourceNotFoundException("Incident not found: "+id));x.setStatus("RESOLVED");x.setResolvedBy(staff);x.setResolvedAt(LocalDateTime.now());return IncidentResponse.from(incidents.save(x));}}
